// ── Design System ──
const H = 38; // standard control height
const R = 8;  // standard border radius
const FONT = "'DM Sans',system-ui,-apple-system,sans-serif";
const C = {ruby:"#9B111E",dark:"#6B0D15",light:"#C4343F",rose:"#FDF2F3",gold:"#D4A853",green:"#1a7f37",purple:"#6366f1",bg:"#fef8f8",card:"#fff",border:"#e0d6d7",borderLight:"#ede6e7",borderFocus:"#9B111E",text:"#24292f",textSec:"#57606a",textMuted:"#888",textFaint:"#bbb"};

const FixedParamsEditor = ({params,defaults,onChange,label,help}) => {
  const p = params || {};
  const d = defaults || {};
  const keys = Object.keys(d);
  const set = (k,v) => onChange({...p,[k]:v});
  const isDefault = k => p[k] === undefined || p[k] === d[k];
  const modified = keys.filter(k=>!isDefault(k)).length;
  return (
    <div style={{background:"#faf8f8",borderRadius:10,border:`1px solid ${C.borderLight}`,padding:"16px 20px",marginTop:8}}>
      {label && <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:6}}>
        <span style={{fontSize:13,fontWeight:600,color:C.dark}}>{label}</span>
        {modified>0 && <span style={{fontSize:10,background:C.rose,color:C.ruby,padding:"2px 10px",borderRadius:10,fontWeight:600}}>{modified} angepasst</span>}
      </div>}
      {help && <div style={{fontSize:12,color:C.textMuted,marginBottom:10,lineHeight:1.5}}>{help}</div>}
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"6px 12px"}}>
        {keys.map(k => {
          const val = p[k] !== undefined ? p[k] : d[k];
          const def = d[k];
          const isNum = typeof def === "number";
          const isBool = typeof def === "boolean";
          const changed = !isDefault(k);
          return (
            <div key={k} style={{display:"flex",alignItems:"center",gap:8,padding:"6px 12px",background:changed?"#FDF2F3":"#fff",borderRadius:R,border:`1px solid ${changed?"#e0b5b9":C.borderLight}`,transition:"all 0.15s"}}>
              <code style={{fontSize:11,fontWeight:600,color:changed?C.ruby:C.textSec,minWidth:120,fontFamily:"'JetBrains Mono',monospace"}}>{k}</code>
              <div style={{flex:1,display:"flex",alignItems:"center",justifyContent:"flex-end",gap:6}}>
                {isBool ? (
                  <div onClick={()=>set(k,!val)} style={{width:34,height:18,borderRadius:9,background:val?C.ruby:"#ccc",position:"relative",cursor:"pointer",flexShrink:0,transition:"background 0.2s"}}>
                    <div style={{width:12,height:12,borderRadius:6,background:"#fff",position:"absolute",top:3,left:val?19:3,transition:"left 0.2s",boxShadow:"0 1px 3px rgba(0,0,0,0.15)"}}/>
                  </div>
                ) : (
                  <input type={isNum?"number":"text"} value={val===null?"":val} onChange={e=>{const v=e.target.value;set(k,isNum?(v===""?def:Number(v)):v===""?def:v)}} style={{width:80,height:30,padding:"0 8px",border:`1.5px solid ${changed?"#d4a0a6":C.border}`,borderRadius:6,fontSize:12,fontFamily:"'JetBrains Mono',monospace",fontWeight:600,background:"#fff",outline:"none",boxSizing:"border-box",textAlign:"right",color:changed?C.ruby:C.text}} onFocus={e=>{e.target.style.borderColor=C.ruby;e.target.style.boxShadow="0 0 0 2px rgba(155,17,30,0.08)"}} onBlur={e=>{e.target.style.borderColor=changed?"#d4a0a6":C.border;e.target.style.boxShadow="none"}}/>
                )}
                {changed && <span style={{fontSize:11,color:C.light,cursor:"pointer",opacity:0.7,lineHeight:1}} onClick={()=>{const next={...p};delete next[k];onChange(next)}} title="Auf Default zurücksetzen">↺</span>}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

