// ── Search Space ──
const SSEditor = ({bl,sp,setSp,fmt}) => {
  const defs=bl==="catboost"?(fmt?CB_FMT:CB):(fmt?LGBM_FMT:LGBM);const cur=sp[bl]||{};
  const g=k=>({low:cur[k]?.low??defs[k].min,high:cur[k]?.high??defs[k].max});
  const s=(k,l,h)=>setSp(p=>({...p,[bl]:{...p[bl],[k]:{low:l,high:h}}}));
  return (
    <div>
      <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:12}}>
        <span style={{fontSize:13.5,fontWeight:700,color:"#6B0D15"}}>{bl==="catboost"?"CatBoost":"LightGBM"} Suchraum</span>
        <span style={{fontSize:10.5,color:"#888",background:"#faf6f6",padding:"2px 10px",borderRadius:10,border:"1px solid #f0eaeb"}}>Optuna low – high</span>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"0 14px"}}>
        {Object.entries(defs).map(([k,d])=>{const r=g(k);return (<RSlider key={k} label={k} min={d.min} max={d.max} step={d.step} low={r.low} high={r.high} type={d.type} onLow={v=>s(k,v,r.high)} onHigh={v=>s(k,r.low,v)}/>);})}
      </div>
    </div>
  );
};

// ── Progress Tracker ──
const ProgressTracker = ({currentStep,error,steps,enabled,completedSteps,stepProgress,stepDurations,totalElapsed}) => {
  const activeSteps = steps.filter(s=>enabled.has(s.id));
  const completedCount = activeSteps.filter(s=>completedSteps.has(s.id)).length;
  const totalCount = activeSteps.length;

  const currentProg = stepProgress || 0;

  return (
    <div style={{margin:"14px 0"}}>
      {/* Overall progress bar */}
      <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:10}}>
        <div style={{flex:1,height:5,background:"#ede6e7",borderRadius:3,overflow:"hidden"}}>
          <div style={{height:"100%",background:"linear-gradient(90deg,#6B0D15,#9B111E)",borderRadius:3,transition:"width 0.5s ease",width:`${totalCount>0?((completedCount+(currentProg/100))/totalCount)*100:0}%`}}/>
        </div>
        <span style={{fontSize:11.5,fontFamily:"monospace",color:"#6B0D15",fontWeight:600,minWidth:60}}>{completedCount}/{totalCount}</span>

      </div>
      {/* Step list */}
      <div style={{borderRadius:10,overflow:"hidden",border:"1px solid #ede6e7"}}>
        {activeSteps.map((st) => {
          const done=completedSteps.has(st.id);
          const active=st.id===currentStep;
          const failed=active&&error;
          const dur = stepDurations[st.id];
          let bg="#fafafa",brd="#e8e2e3",col="#bbb",icon="○",fw=400;
          if(done){bg="#f0faf3";brd="#1a7f37";col="#1a7f37";icon="✓";fw=500;}
          if(active&&!failed){bg="#FDF2F3";brd="#9B111E";col="#9B111E";icon="›";fw=600;}
          if(failed){bg="#fff5f5";brd="#cf222e";col="#cf222e";icon="✕";fw=600;}
          return (
            <div key={st.id} style={{borderLeft:`3px solid ${brd}`,borderBottom:"1px solid #f5f0f0",background:bg}}>
              <div style={{display:"flex",alignItems:"center",gap:14,padding:"10px 18px"}}>
                <span style={{fontWeight:700,fontSize:16,color:col,width:18,textAlign:"center",fontFamily:"monospace"}}>{icon}</span>
                <span style={{fontSize:13.5,fontWeight:fw,color:active||done?col:"#888",flex:1}}>{st.label}</span>
                {active&&!failed&&<span style={{fontSize:11,color:"#9B111E",fontWeight:500}}>{stepProgress||0}%</span>}
                {done&&dur!=null&&<span style={{fontSize:10.5,color:"#1a7f37",fontWeight:500}}>{dur.toFixed(1)}s</span>}
                {failed&&<span style={{fontSize:11,color:"#cf222e",fontWeight:600}}>Fehler</span>}
              </div>
              {active&&!failed&&<div style={{height:4,background:"#ede6e7",margin:"0 18px 8px"}}><div style={{height:"100%",background:"linear-gradient(90deg,#9B111E,#C4343F)",borderRadius:2,transition:"width 0.3s",width:(stepProgress||0)+"%"}}/></div>}
            </div>
          );
        })}
      </div>
    </div>
  );
};

