    if(!hasFiles && !hasModels) s.data = {st:"required",detail:"X/T/Y-Dateien + Modelle fehlen"};
    else if(!hasFiles) s.data = {st:"required",detail:"X/T/Y-Dateien fehlen"};
    else if(!hasModels) s.data = {st:"required",detail:"Keine Modelle ausgewählt"};
